mapper.select:
SELECT ID, CERTIFI_TYPE, CERTIFI_CODE, CERTIFICATE_NAME, CERTIFI_NUMBER, CERTIFI_USER, CERTIFI_USER_NAME, EXPIRE_DATE, VALID_DATE, CERTIFI_STATE, FIRST_DATE, REMARK, DEL_FLAG, USE_ORG_ID, USE_ORG_NAME, CERTIFICATION_AUTHORITY, EXAM_ORG, IS_EMPLOY FROM M_PECIAL_PERSON where DEL_FLAG = 0
AND CERTIFI_USER_NAME LIKE #{certifiUserPattern}
AND CERTIFI_NUMBER LIKE #{certifiNumberPattern}
AND CERTIFI_CODE LIKE #{certifiCodePattern}
AND USE_ORG_ID = #{useOrgId}
ORDER BY EXPIRE_DATE ASC
